const LandingPage = () => {
  const [email, setEmail] = React.useState('');
  const [submitted, setSubmitted] = React.useState(false);

  const features = [
    { icon: '⚡', title: 'Lightning Fast', desc: 'Optimized performance out of the box with zero config required.' },
    { icon: '🔒', title: 'Enterprise Security', desc: 'Bank-grade encryption and compliance built into every layer.' },
    { icon: '📊', title: 'Real-time Analytics', desc: 'Track what matters with live dashboards and insights.' },
    { icon: '🔄', title: 'Auto Scaling', desc: 'Infrastructure that grows with you from day one to millions.' }
  ];

  const handleSubmit = (e) => {
    e.preventDefault();
    if (email.trim()) setSubmitted(true);
  };

  const styles = {
    page: {
      fontFamily: 'system-ui, -apple-system, sans-serif',
      color: '#1e293b',
      background: '#fff'
    },
    navbar: {
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'space-between',
      padding: '16px 24px',
      borderBottom: '1px solid #f1f5f9'
    },
    logo: {
      fontSize: 20,
      fontWeight: 800,
      color: '#0f172a'
    },
    navLinks: {
      display: 'flex',
      gap: 20,
      fontSize: 14,
      fontWeight: 500,
      color: '#475569'
    },
    hero: {
      textAlign: 'center',
      padding: '56px 24px',
      background: 'linear-gradient(180deg, #eff6ff 0%, #fff 100%)'
    },
    heroTitle: {
      fontSize: 36,
      fontWeight: 800,
      lineHeight: 1.15,
      marginBottom: 16,
      color: '#0f172a'
    },
    heroSubtitle: {
      fontSize: 17,
      color: '#475569',
      maxWidth: 520,
      margin: '0 auto 28px',
      lineHeight: 1.6
    },
    ctaRow: {
      display: 'flex',
      justifyContent: 'center',
      gap: 12,
      flexWrap: 'wrap'
    },
    btnPrimary: {
      padding: '12px 24px',
      borderRadius: 10,
      border: 'none',
      background: '#2563eb',
      color: '#fff',
      fontWeight: 700,
      fontSize: 15,
      cursor: 'pointer'
    },
    btnSecondary: {
      padding: '12px 24px',
      borderRadius: 10,
      border: '1px solid #cbd5e1',
      background: '#fff',
      color: '#334155',
      fontWeight: 700,
      fontSize: 15,
      cursor: 'pointer'
    },
    featuresSection: {
      padding: '48px 24px',
      background: '#f8fafc'
    },
    sectionTitle: {
      fontSize: 22,
      fontWeight: 700,
      textAlign: 'center',
      marginBottom: 28
    },
    grid: {
      display: 'grid',
      gridTemplateColumns: 'repeat(auto-fit, minmax(180px, 1fr))',
      gap: 20,
      maxWidth: 900,
      margin: '0 auto'
    },
    featureCard: {
      background: '#fff',
      borderRadius: 12,
      padding: 24,
      boxShadow: '0 1px 3px rgba(0,0,0,0.06)',
      border: '1px solid #e2e8f0',
      textAlign: 'center'
    },
    featureIcon: {
      fontSize: 32,
      marginBottom: 12
    },
    featureTitle: {
      fontSize: 15,
      fontWeight: 700,
      marginBottom: 8
    },
    featureDesc: {
      fontSize: 13,
      color: '#64748b',
      lineHeight: 1.5
    },
    ctaSection: {
      padding: '48px 24px',
      textAlign: 'center'
    },
    ctaCard: {
      background: '#0f172a',
      color: '#fff',
      borderRadius: 16,
      padding: '40px 24px',
      maxWidth: 560,
      margin: '0 auto'
    },
    ctaTitle: {
      fontSize: 22,
      fontWeight: 700,
      marginBottom: 12
    },
    ctaText: {
      fontSize: 15,
      color: '#cbd5e1',
      marginBottom: 20,
      lineHeight: 1.5
    },
    emailForm: {
      display: 'flex',
      gap: 8,
      justifyContent: 'center',
      flexWrap: 'wrap'
    },
    emailInput: {
      padding: '10px 14px',
      borderRadius: 8,
      border: '1px solid #334155',
      background: '#1e293b',
      color: '#fff',
      fontSize: 14,
      outline: 'none',
      minWidth: 220
    },
    footer: {
      textAlign: 'center',
      padding: 20,
      fontSize: 12,
      color: '#94a3b8',
      borderTop: '1px solid #f1f5f9'
    }
  };

  return (
    <div style={styles.page}>
      <nav style={styles.navbar}>
        <div style={styles.logo}>Titan</div>
        <div style={styles.navLinks}>
          <span>Product</span>
          <span>Pricing</span>
          <span>Docs</span>
        </div>
      </nav>

      <section style={styles.hero}>
        <div style={styles.heroTitle}>Build faster with Titan</div>
        <div style={styles.heroSubtitle}>
          The all-in-one platform for shipping software. From idea to production in minutes, not months.
        </div>
        <div style={styles.ctaRow}>
          <button style={styles.btnPrimary}>Get Started Free</button>
          <button style={styles.btnSecondary}>View Demo</button>
        </div>
      </section>

      <section style={styles.featuresSection}>
        <div style={styles.sectionTitle}>Why teams choose Titan</div>
        <div style={styles.grid}>
          {features.map((f, i) => (
            <div key={i} style={styles.featureCard}>
              <div style={styles.featureIcon}>{f.icon}</div>
              <div style={styles.featureTitle}>{f.title}</div>
              <div style={styles.featureDesc}>{f.desc}</div>
            </div>
          ))}
        </div>
      </section>

      <section style={styles.ctaSection}>
        <div style={styles.ctaCard}>
          <div style={styles.ctaTitle}>Ready to launch?</div>
          <div style={styles.ctaText}>Join 10,000+ builders shipping with Titan today.</div>
          {submitted ? (
            <div style={{ fontSize: 16, fontWeight: 600, color: '#4ade80' }}>✓ You are on the list!</div>
          ) : (
            <form style={styles.emailForm} onSubmit={handleSubmit}>
              <input
                style={styles.emailInput}
                placeholder="you@company.com"
                value={email}
                onChange={e => setEmail(e.target.value)}
              />
              <button style={styles.btnPrimary} type="submit">Join Waitlist</button>
            </form>
          )}
        </div>
      </section>

      <footer style={styles.footer}>
        © 2025 Titan Inc. All rights reserved.
      </footer>
    </div>
  );
};
render(<LandingPage/>);
